import React, { useState, useEffect } from "react";

export default function FormTratamento({
  denteSelecionado,
  onAdicionarTratamento,
  profissionais,
}) {
  const [form, setForm] = useState({
    plano: "Particular",
    tratamento: "",
    dente: denteSelecionado || "",
    valor: "",
    profissional: profissionais[0] || "",
  });

  useEffect(() => {
    setForm(f => ({ ...f, dente: denteSelecionado || "" }));
  }, [denteSelecionado]);

  function handleChange(e) {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    if (!form.tratamento || !form.dente || !form.valor || !form.profissional) return;
    onAdicionarTratamento({
      ...form,
      status: "aberto",
      criadoEm: new Date().toISOString(),
      id: Math.random().toString(36).slice(2),
    });
    setForm(f => ({
      ...f,
      tratamento: "",
      valor: "",
    }));
  }

  return (
    <form onSubmit={handleSubmit} className="bg-gray-50 p-4 rounded shadow mb-6">
      <h3 className="text-lg font-semibold mb-2">Adicionar tratamento</h3>
      <div className="flex flex-wrap gap-4 mb-4">
        <div>
          <label className="text-xs text-gray-500">Plano*</label>
          <select
            name="plano"
            className="block w-32 border rounded px-2 py-1"
            value={form.plano}
            onChange={handleChange}
          >
            <option value="Particular">Particular</option>
            <option value="Convênio">Convênio</option>
          </select>
        </div>
        <div>
          <label className="text-xs text-gray-500">Tratamento*</label>
          <input
            name="tratamento"
            className="block w-48 border rounded px-2 py-1"
            value={form.tratamento}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Dente/Região*</label>
          <input
            name="dente"
            className="block w-20 border rounded px-2 py-1"
            value={form.dente}
            onChange={handleChange}
            required
            readOnly
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Valor*</label>
          <input
            name="valor"
            type="number"
            className="block w-24 border rounded px-2 py-1"
            value={form.valor}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Profissional*</label>
          <select
            name="profissional"
            className="block w-40 border rounded px-2 py-1"
            value={form.profissional}
            onChange={handleChange}
            required
          >
            {profissionais.map(p => (
              <option key={p} value={p}>{p}</option>
            ))}
          </select>
        </div>
      </div>
      <button
        type="submit"
        className="bg-green-600 text-white px-6 py-2 rounded font-semibold"
      >
        ADICIONAR TRATAMENTO
      </button>
    </form>
  );
}
